xpath.script:
(function () {
'use strict';

function ensureZipCode() {
var zipInput = document.getElementById('o_zip');
if (zipInput) {
if (!zipInput.value || zipInput.value.trim() === '') {
zipInput.value = '00000';
}
zipInput.setAttribute('readonly', 'readonly');
}
}

document.addEventListener('DOMContentLoaded', function () {
ensureZipCode();

var form = document.querySelector('form.checkout_autoformat');
if (form) {
form.addEventListener('submit', function () {
ensureZipCode();
}, true);
}

var submitButton = document.getElementById('save_address');
if (submitButton) {
submitButton.addEventListener('click', function () {
ensureZipCode();
}, true);
}
});
})();


document.addEventListener('DOMContentLoaded', function () {
    const noteInput = document.getElementById('order_note_input');
    if (noteInput) {
        let timeout;
        noteInput.addEventListener('input', function () {
            clearTimeout(timeout);
            timeout = setTimeout(function () {
                fetch('/shop/save_order_note', {
                    method: 'POST',
                    headers: {'Content-Type': 'application/json'},
                    body: JSON.stringify({
                        jsonrpc: '2.0',
                        method: 'call',
                        params: {order_note: noteInput.value},
                    }),
                })
                .then(response => response.json())
                .then(data => {
                    if (data.result && data.result.success) {
                        console.log('Note saved!');
                    }
                })
                .catch(error => {
                    console.error('Error saving note:', error);
                });
        }, 500);
        });
    }
});
